class ErrorBoundary extends Component {
  constructor(p){super(p);this.state={err:null}}
  static getDerivedStateFromError(e){return{err:e}}
  render(){if(this.state.err)return <div style={{padding:'2rem',textAlign:'center'}}><h2>Napaka</h2><p>{this.state.err?.message}</p><button onClick={()=>{this.setState({err:null});window.location.reload()}} style={{padding:'8px 16px',background:'#2563eb',color:'#fff',border:'none',borderRadius:6,cursor:'pointer'}}>Ponovno naloži</button></div>;return this.props.children}
}
function simpleHash(s){let h=0;for(let i=0;i<s.length;i++){h=((h<<5)-h)+s.charCodeAt(i);h=h&h}return Math.abs(h).toString(36)+s.length.toString(36)}
async function hashPwd(p,salt){if(typeof crypto!=='undefined'&&crypto.subtle){const d=new TextEncoder().encode(salt+p);const b=await crypto.subtle.digest('SHA-256',d);return Array.from(new Uint8Array(b)).map(x=>x.toString(16).padStart(2,'0')).join('')}return simpleHash(salt+p+salt)}
